import{_ as l,o as t,c as o,a2 as i}from"./chunks/framework.Bjylvv1V.js";const g=JSON.parse('{"title":"관리비 부과","description":"","frontmatter":{},"headers":[],"relativePath":"guide/scenarios/billing.md","filePath":"guide/scenarios/billing.md","lastUpdated":1771991831000}'),r={name:"guide/scenarios/billing.md"};function e(s,a,n,h,c,d){return t(),o("div",null,[...a[0]||(a[0]=[i(`<h1 id="관리비-부과" tabindex="-1">관리비 부과 <a class="header-anchor" href="#관리비-부과" aria-label="Permalink to &quot;관리비 부과&quot;">​</a></h1><blockquote><p><strong>소요 시간</strong>: 약 30분 | <strong>난이도</strong>: ★★★ | <strong>주기</strong>: 매월 3주차</p></blockquote><p>검침 데이터와 기초정보를 바탕으로 각 세대에 관리비를 산정·부과하는 전체 프로세스입니다.</p><h2 id="전체-흐름" tabindex="-1">전체 흐름 <a class="header-anchor" href="#전체-흐름" aria-label="Permalink to &quot;전체 흐름&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 사전 확인        (5분)  → 기초정보, 검침 완료 여부</span></span>
<span class="line"><span>2. 부과기초작업      (3분)  → 부과 기간·수납 기간 설정</span></span>
<span class="line"><span>3. 별도금액 등록     (5분)  → 추가/차감 금액 입력</span></span>
<span class="line"><span>4. 관리비 부과처리   (10분) → 발생금액 입력·계산</span></span>
<span class="line"><span>5. 총괄표 확인      (3분)  → 전월 대비 확인</span></span>
<span class="line"><span>6. 부과마감         (2분)  → 확정 처리</span></span>
<span class="line"><span>7. 고지서 출력/전송  (2분)  → 인쇄 또는 전자고지</span></span></code></pre></div><hr><h2 id="_1단계-사전-확인-5분" tabindex="-1">1단계: 사전 확인 (5분) <a class="header-anchor" href="#_1단계-사전-확인-5분" aria-label="Permalink to &quot;1단계: 사전 확인 (5분)&quot;">​</a></h2><p><strong>왜 필요한가?</strong> 검침이 완료되지 않으면 부과 금액이 정확하지 않고, 기초정보가 틀리면 세대별 금액이 잘못 산정됩니다.</p><h3 id="체크리스트" tabindex="-1">체크리스트 <a class="header-anchor" href="#체크리스트" aria-label="Permalink to &quot;체크리스트&quot;">​</a></h3><ul><li>[ ] 모든 검침(전기·수도·온수·가스·난방)이 완료되었는가?</li><li>[ ] 신규 입주·전출 세대가 반영되었는가?</li><li>[ ] 부과 기준 단가 변경 사항이 있는가?</li><li>[ ] 부과제외 세대 등록이 최신 상태인가?</li></ul><h3 id="확인-방법" tabindex="-1">확인 방법 <a class="header-anchor" href="#확인-방법" aria-label="Permalink to &quot;확인 방법&quot;">​</a></h3><table tabindex="0"><thead><tr><th>확인 항목</th><th>메뉴 경로</th><th>화면 코드</th></tr></thead><tbody><tr><td>검침 완료</td><td><a href="/insp/">검침</a> &gt; 각 검침 메뉴에서 조회</td><td>INSP1120 등</td></tr><tr><td>기초정보</td><td><a href="/impo/">부과</a> &gt; <a href="/impo/basic.html">기초정보</a></td><td>IMPO1020</td></tr><tr><td>부과제외세대</td><td><a href="/impo/">부과</a> &gt; <a href="/impo/basic.html">기초정보</a> &gt; 부과제외세대등록</td><td>IMPO1040</td></tr></tbody></table><hr><h2 id="_2단계-부과기초작업-3분" tabindex="-1">2단계: 부과기초작업 (3분) <a class="header-anchor" href="#_2단계-부과기초작업-3분" aria-label="Permalink to &quot;2단계: 부과기초작업 (3분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 부과 &gt; <a href="/impo/process.html">부과처리</a> &gt; 부과기초작업 (IMPO2005)</p></blockquote><p>이번 달 부과의 기본 틀을 만드는 단계입니다.</p><h3 id="절차" tabindex="-1">절차 <a class="header-anchor" href="#절차" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li><strong>부과기초작업</strong> 화면 진입</li><li><strong>행추가</strong> 버튼 클릭</li><li>아래 항목 입력: <ul><li><strong>부과 기간</strong>: 당월 1일 ~ 말일 (예: 2026-03-01 ~ 2026-03-31)</li><li><strong>수납 기간</strong>: 부과 월 포함 수납 허용 기간</li><li><strong>납부 기한</strong>: 보통 다음 달 말일</li></ul></li><li><strong>저장</strong> 클릭</li></ol><div class="warning custom-block"><p class="custom-block-title">주의</p><p>부과기초작업을 먼저 완료해야 관리비부과처리를 진행할 수 있습니다. 순서를 건너뛰면 부과처리 화면에서 데이터가 조회되지 않습니다.</p></div><hr><h2 id="_3단계-별도금액-등록-5분" tabindex="-1">3단계: 별도금액 등록 (5분) <a class="header-anchor" href="#_3단계-별도금액-등록-5분" aria-label="Permalink to &quot;3단계: 별도금액 등록 (5분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 부과 &gt; <a href="/impo/process.html">부과처리</a> &gt; 별도금액등록 (IMPO2010)</p></blockquote><p>자동 계산되지 않는 추가/차감 금액을 세대별로 입력합니다.</p><h3 id="언제-사용하나" tabindex="-1">언제 사용하나? <a class="header-anchor" href="#언제-사용하나" aria-label="Permalink to &quot;언제 사용하나?&quot;">​</a></h3><ul><li>개별 세대 추가 부과 (예: 인테리어 공사 보증금)</li><li>관리비 감면 (예: 경로우대 할인)</li><li>전월 오류 조정 (예: 과다 부과분 차감)</li></ul><h3 id="절차-1" tabindex="-1">절차 <a class="header-anchor" href="#절차-1" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>별도금액등록 화면 진입</li><li>해당 세대의 동·호 선택</li><li>부과항목 선택 후 금액 입력 <ul><li><strong>(+)</strong> 추가 부과</li><li><strong>(-)</strong> 차감</li><li><strong>(=)</strong> 기존 금액 대체</li><li><strong>(/)</strong> 나누기 적용</li></ul></li><li><strong>저장</strong> 클릭</li></ol><div class="tip custom-block"><p class="custom-block-title">대량 등록</p><p>여러 세대를 한 번에 처리하려면 <strong>엑셀 업로드</strong>를 사용하세요. 엑셀 양식: 부서코드, 동, 호수, 항목코드, 정보, 금액 비고. 파일 형식은 <strong>Excel 97-2003(.xls)</strong> 이어야 합니다.</p></div><hr><h2 id="_4단계-관리비-부과처리-10분" tabindex="-1">4단계: 관리비 부과처리 (10분) <a class="header-anchor" href="#_4단계-관리비-부과처리-10분" aria-label="Permalink to &quot;4단계: 관리비 부과처리 (10분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 부과 &gt; <a href="/impo/process.html">부과처리</a> &gt; 관리비부과처리 (IMPO2020)</p></blockquote><p>실제 관리비를 계산하고 세대별 금액을 확정하는 핵심 단계입니다.</p><h3 id="절차-2" tabindex="-1">절차 <a class="header-anchor" href="#절차-2" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>부과 연월 선택</li><li>각 부과항목별 <strong>발생금액</strong> 입력 <ul><li>발생금액 = 해당 항목의 총액 (예: 공용전기료 총액)</li></ul></li><li><strong>계산</strong> 버튼 클릭 <ul><li>시스템이 자동으로 세대별 금액을 배분 (면적·세대수 기준)</li><li>계산식: 세대별 단가 = 발생금액 ÷ 총 부과 대상</li></ul></li><li>하단 그리드에서 <strong>세대별 금액</strong> 확인 <ul><li>이상 금액이 있으면 직접 수정 가능</li></ul></li><li><strong>저장</strong> 클릭</li></ol><h3 id="확인-포인트" tabindex="-1">확인 포인트 <a class="header-anchor" href="#확인-포인트" aria-label="Permalink to &quot;확인 포인트&quot;">​</a></h3><ul><li>[ ] 각 항목의 발생금액이 전월과 크게 차이나지 않는가?</li><li>[ ] 세대별 배분 결과가 합리적인가?</li><li>[ ] 별도금액(3단계)이 정상 반영되었는가?</li></ul><div class="warning custom-block"><p class="custom-block-title">분리부과가 필요한 경우</p><p>입주자/사업자/소유자별로 관리비를 나눠야 하는 단지는 <strong>분리부과처리</strong>(IMPO2030)를 추가로 실행하세요. 2분리(입주자/사업자) 또는 3분리(입주자/사업자/소유자) 선택이 가능합니다.</p></div><hr><h2 id="_5단계-총괄표-확인-3분" tabindex="-1">5단계: 총괄표 확인 (3분) <a class="header-anchor" href="#_5단계-총괄표-확인-3분" aria-label="Permalink to &quot;5단계: 총괄표 확인 (3분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 부과 &gt; <a href="/impo/process.html">부과처리</a> &gt; 총괄표 (IMPO2040)</p></blockquote><p>부과 결과를 전월과 비교하여 이상 여부를 최종 점검합니다.</p><h3 id="절차-3" tabindex="-1">절차 <a class="header-anchor" href="#절차-3" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>총괄표 화면 진입</li><li>당월 부과 총액 vs 전월 부과 총액 비교</li><li>항목별 증감 내역 확인</li></ol><h3 id="확인-포인트-1" tabindex="-1">확인 포인트 <a class="header-anchor" href="#확인-포인트-1" aria-label="Permalink to &quot;확인 포인트&quot;">​</a></h3><ul><li>[ ] 전월 대비 총액 변동이 합리적인가? (계절 요인 등 고려)</li><li>[ ] 특정 항목이 급격히 변동하지 않았는가?</li><li>[ ] 세대수 변동(전출입)이 정확히 반영되었는가?</li></ul><hr><h2 id="_6단계-부과마감-2분" tabindex="-1">6단계: 부과마감 (2분) <a class="header-anchor" href="#_6단계-부과마감-2분" aria-label="Permalink to &quot;6단계: 부과마감 (2분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 부과 &gt; <a href="/impo/closing.html">부과마감</a> (IMPO9010)</p></blockquote><p>부과 내역을 확정합니다. <strong>마감 후에는 수정이 불가</strong>합니다.</p><h3 id="절차-4" tabindex="-1">절차 <a class="header-anchor" href="#절차-4" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>부과마감 화면 진입</li><li>부과 연월 선택</li><li>항목별 금액 최종 확인</li><li><strong>비율</strong> 버튼 클릭 (항목별 비율 확인)</li><li><strong>마감</strong> 버튼 클릭</li></ol><div class="danger custom-block"><p class="custom-block-title">되돌리기 불가</p><p>부과마감 후에는 수정할 수 없습니다. 반드시 총괄표와 세대별 금액을 확인한 뒤 마감하세요. 마감 후 오류를 발견하면 다음 달 <strong>별도금액</strong>으로 조정해야 합니다.</p></div><hr><h2 id="_7단계-고지서-출력-전송-2분" tabindex="-1">7단계: 고지서 출력/전송 (2분) <a class="header-anchor" href="#_7단계-고지서-출력-전송-2분" aria-label="Permalink to &quot;7단계: 고지서 출력/전송 (2분)&quot;">​</a></h2><p>마감이 완료되면 세대에 고지서를 전달합니다.</p><h3 id="방법-1-인쇄-출력" tabindex="-1">방법 1: 인쇄 출력 <a class="header-anchor" href="#방법-1-인쇄-출력" aria-label="Permalink to &quot;방법 1: 인쇄 출력&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 부과 &gt; <a href="/impo/closing.html">부과마감</a> &gt; 출력의뢰(부과마감)</p></blockquote><ol><li>출력의뢰 화면에서 동·호 범위 입력</li><li>출력 요청 실행</li></ol><h3 id="방법-2-전자고지서" tabindex="-1">방법 2: 전자고지서 <a class="header-anchor" href="#방법-2-전자고지서" aria-label="Permalink to &quot;방법 2: 전자고지서&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 부과 &gt; <a href="/impo/closing.html">부과마감</a> &gt; 전자고지서 (IMPO9011)</p></blockquote><ol><li>전자고지서 화면 진입</li><li>부과 연월 확인</li><li>내용 확인 후 <strong>전송</strong> 실행</li></ol><hr><h2 id="자주-발생하는-문제" tabindex="-1">자주 발생하는 문제 <a class="header-anchor" href="#자주-발생하는-문제" aria-label="Permalink to &quot;자주 발생하는 문제&quot;">​</a></h2><h3 id="부과처리-화면에-데이터가-안-나와요" tabindex="-1">부과처리 화면에 데이터가 안 나와요 <a class="header-anchor" href="#부과처리-화면에-데이터가-안-나와요" aria-label="Permalink to &quot;부과처리 화면에 데이터가 안 나와요&quot;">​</a></h3><p><strong>원인</strong>: 부과기초작업(2단계)이 완료되지 않았습니다. <strong>해결</strong>: 부과기초작업에서 해당 월의 부과 기간을 먼저 등록하세요.</p><h3 id="특정-세대가-부과-목록에-없어요" tabindex="-1">특정 세대가 부과 목록에 없어요 <a class="header-anchor" href="#특정-세대가-부과-목록에-없어요" aria-label="Permalink to &quot;특정 세대가 부과 목록에 없어요&quot;">​</a></h3><p><strong>원인</strong>: 부과제외세대로 등록되어 있거나, 입주 처리가 안 된 세대입니다. <strong>해결</strong>: <a href="/impo/basic.html">기초정보</a> &gt; 부과제외세대등록(IMPO1040)에서 확인하고, <a href="/occp/move-in.html">입주처리</a>를 확인하세요.</p><h3 id="전월보다-금액이-크게-달라요" tabindex="-1">전월보다 금액이 크게 달라요 <a class="header-anchor" href="#전월보다-금액이-크게-달라요" aria-label="Permalink to &quot;전월보다 금액이 크게 달라요&quot;">​</a></h3><p><strong>원인</strong>: 검침값 오류, 단가 변경, 별도금액 입력 오류 등 <strong>해결</strong>: 총괄표(IMPO2040)에서 항목별로 전월 대비 비교하여 변동 원인을 파악하세요.</p><h3 id="마감-후-오류를-발견했어요" tabindex="-1">마감 후 오류를 발견했어요 <a class="header-anchor" href="#마감-후-오류를-발견했어요" aria-label="Permalink to &quot;마감 후 오류를 발견했어요&quot;">​</a></h3><p><strong>원인</strong>: 마감 후에는 부과 내역 수정이 불가합니다. <strong>해결</strong>: 다음 달 부과 시 <strong>별도금액등록</strong>(IMPO2010)에서 (+)추가 또는 (-)차감으로 조정하세요.</p><hr><h2 id="관련-메뉴" tabindex="-1">관련 메뉴 <a class="header-anchor" href="#관련-메뉴" aria-label="Permalink to &quot;관련 메뉴&quot;">​</a></h2><ul><li><a href="/impo/basic.html">부과 기초정보</a> - 부과그룹, 항목, 단가 설정</li><li><a href="/impo/process.html">부과처리</a> - 부과 실행 상세</li><li><a href="/impo/inquiry.html">관리비부과조회</a> - 고지서·조정대장 확인</li><li><a href="/impo/closing.html">부과마감</a> - 마감 및 고지서 출력</li><li><a href="/insp/">검침</a> - 부과 전 검침 완료 필수</li></ul>`,74)])])}const u=l(r,[["render",e]]);export{g as __pageData,u as default};
